import{_ as a,o as i,c as e,ai as t}from"./chunks/framework.ampVZV4B.js";const p=JSON.parse('{"title":"阶段一：大模型（LLM）与 Agent 入门学习规划【按目标细拆】","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/ai/phase1-llm-agent.md","filePath":"tech-system/ai/phase1-llm-agent.md"}'),r={name:"tech-system/ai/phase1-llm-agent.md"};function n(o,l,s,h,g,d){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="阶段一-大模型-llm-与-agent-入门学习规划【按目标细拆】" tabindex="-1">阶段一：大模型（LLM）与 Agent 入门学习规划【按目标细拆】 <a class="header-anchor" href="#阶段一-大模型-llm-与-agent-入门学习规划【按目标细拆】" aria-label="Permalink to “阶段一：大模型（LLM）与 Agent 入门学习规划【按目标细拆】”">​</a></h1><blockquote><p>这篇只管一件事：<strong>帮你把“大模型 + Agent 入门”拆成可以执行的学习计划</strong>，不同学习目的有不同重点。</p></blockquote><hr><h2 id="_1-学习前提-适合人群" tabindex="-1">1. 学习前提 &amp; 适合人群 <a class="header-anchor" href="#_1-学习前提-适合人群" aria-label="Permalink to “1. 学习前提 &amp; 适合人群”">​</a></h2><ul><li>会一门后端或脚本语言（Java / JavaScript / Python 任一即可）。</li><li>目标不是做研究，而是：<strong>尽快用 AI 提升工作/学习效率，顺便打一点 AI 项目基础</strong>。</li></ul><hr><h2 id="_2-按不同学习目的怎么用这一阶段" tabindex="-1">2. 按不同学习目的怎么用这一阶段 <a class="header-anchor" href="#_2-按不同学习目的怎么用这一阶段" aria-label="Permalink to “2. 按不同学习目的怎么用这一阶段”">​</a></h2><h3 id="目的-a-先用-ai-提升效率-找远程-6000-的主力方向" tabindex="-1">目的 A：先用 AI 提升效率（找远程 6000 的主力方向） <a class="header-anchor" href="#目的-a-先用-ai-提升效率-找远程-6000-的主力方向" aria-label="Permalink to “目的 A：先用 AI 提升效率（找远程 6000 的主力方向）”">​</a></h3><ul><li>重点放在： <ul><li>会在网页端用 LLM（ChatGPT / 通义等）<strong>写代码、查 bug、解释概念</strong>。</li><li>会写几类固定 Prompt：面试 Q&amp;A、项目包装、学习总结。</li></ul></li><li>对 API / Agent 部分，只要<strong>知道概念</strong>即可，代码可以以后再补。</li></ul><h3 id="目的-b-想做小工具-个人项目-副业-提效工具" tabindex="-1">目的 B：想做小工具 / 个人项目（副业 / 提效工具） <a class="header-anchor" href="#目的-b-想做小工具-个人项目-副业-提效工具" aria-label="Permalink to “目的 B：想做小工具 / 个人项目（副业 / 提效工具）”">​</a></h3><ul><li>在 A 的基础上，再加： <ul><li>至少会用一种语言通过 API 调用模型（Java / JS / Python）。</li><li>能做 1～2 个实用小工具（如：面试题生成器、学习笔记总结器）。</li></ul></li></ul><h3 id="目的-c-以后可能往-ai-方向发展" tabindex="-1">目的 C：以后可能往 AI 方向发展 <a class="header-anchor" href="#目的-c-以后可能往-ai-方向发展" aria-label="Permalink to “目的 C：以后可能往 AI 方向发展”">​</a></h3><ul><li>在 B 的基础上，再加： <ul><li>多看几种模型（GPT / Qwen / LLaMA）与费用/能力差异。</li><li>初步接触 LangChain 这类 Agent 框架，理解“模型 + 工具 + 规划”这一整套。</li></ul></li></ul><blockquote><p>对你现在来说：<strong>A + B 足够</strong>，C 可以作为“顺手积累”。</p></blockquote><hr><h2 id="_3-时间规划建议-按-2-周来安排" tabindex="-1">3. 时间规划建议（按 2 周来安排） <a class="header-anchor" href="#_3-时间规划建议-按-2-周来安排" aria-label="Permalink to “3. 时间规划建议（按 2 周来安排）”">​</a></h2><h3 id="第-1-周-大模型-llm-使用与-prompt-基础" tabindex="-1">第 1 周：大模型（LLM）使用与 Prompt 基础 <a class="header-anchor" href="#第-1-周-大模型-llm-使用与-prompt-基础" aria-label="Permalink to “第 1 周：大模型（LLM）使用与 Prompt 基础”">​</a></h3><p><strong>第 1～2 天：熟悉模型 &amp; 控制台</strong></p><ul><li>选择并熟悉 1～2 个平台： <ul><li>一个主力模型（如 GPT / 通义）+ 一个备用。</li></ul></li><li>刻意练习： <ul><li>让模型帮你<strong>解释 docs 里某篇 Java/数据库/Redis 文档</strong>，看它讲得是否通俗。</li><li>让它根据你的实际项目，生成<strong>自我介绍 + 项目亮点</strong>。</li></ul></li></ul><p><strong>第 3～5 天：系统学习 Prompt 模式</strong></p><ul><li>自建一个 “Prompt 模板库”（可以放在你现在的 VitePress 仓库里）： <ul><li>面试提问 &amp; 答案生成模板。</li><li>学习总结模板（输入一篇文档，输出 3～5 个要点 + 1 个小例子）。</li><li>代码重构模板（让它优化你的 Service / DAO 代码）。</li></ul></li><li>要求： <ul><li>每天至少<strong>用模板生成一篇“面试问答”或“学习总结”</strong>，存进你的 docs 里，自己再过一遍改成自己的话。</li></ul></li></ul><h3 id="第-2-周-api-调用-简单-agent-体验" tabindex="-1">第 2 周：API 调用 + 简单 Agent 体验 <a class="header-anchor" href="#第-2-周-api-调用-简单-agent-体验" aria-label="Permalink to “第 2 周：API 调用 + 简单 Agent 体验”">​</a></h3><p><strong>第 6～8 天：API 调用练手</strong></p><ul><li>选一个你最熟的语言栈： <ul><li>Java（配合 Spring Boot）、Node.js、或 Python 任一。</li></ul></li><li>参考官方 Quickstart，照抄一个最简单的调用示例，然后改成： <ul><li>从命令行 / Web 表单读取问题。</li><li>调用 LLM 接口输出结果。</li></ul></li></ul><p><strong>第 9～14 天：做 1～2 个小工具</strong></p><p>推荐和你当前网站紧密结合的小项目：</p><ul><li><p><strong>工具 1：面试题生成器</strong></p><ul><li>输入：某个文档路径或模块名（如“数据库事务与锁”）。</li><li>逻辑：脚本读取对应 Markdown 内容 → 作为 context 发给 LLM → 让它生成 N 道题 + 答案。</li><li>输出：生成新的 Markdown 文件，直接放进 <code>/docs/</code> 里，用来后续复习。</li></ul></li><li><p><strong>工具 2：学习总结助手</strong></p><ul><li>输入：一篇你写完的学习笔记或当天学的模块名。</li><li>逻辑：LLM 帮你输出“3 点总结 + 1 个口语化解释 + 1 段面试话术”。</li><li>输出：追加在原文档后，或生成 <code>-summary.md</code> 文件。</li></ul></li></ul><blockquote><p>这两个工具非常贴合你现在的“面试学习网站”，做出来后，你每天学新内容都可以用它们来复盘。</p></blockquote><hr><h2 id="_4-agent-入门部分如何规划-保持轻量" tabindex="-1">4. Agent 入门部分如何规划（保持轻量） <a class="header-anchor" href="#_4-agent-入门部分如何规划-保持轻量" aria-label="Permalink to “4. Agent 入门部分如何规划（保持轻量）”">​</a></h2><p><strong>学习目标：</strong><br> 在这一阶段，<strong>只要搞明白 Agent 是“模型 + 工具 + 任务拆解”就够</strong>，不需要一开始就写很复杂的多 Agent 系统。</p><p><strong>建议做法：</strong></p><ul><li>选一个简单工具 API：天气 / 汇率 / 股票行情 任一。</li><li>用 LangChain 或自己简单写“工具调用逻辑”： <ol><li>用户自然语言输入（如：“帮我看下今天北京天气，适不适合跑步？”）。</li><li>模型先决定要不要调用天气 API。</li><li>如果调用，拿到结果后再生成自然语言解释。</li></ol></li></ul><p>如果你觉得 LangChain 上手成本偏高，也可以先只用“手写代码 + 单次 LLM 调用”的方式模拟 Agent 流程，了解概念即可。</p><hr><h2 id="_5-如何和你当前的-java-面试主线结合" tabindex="-1">5. 如何和你当前的 Java 面试主线结合 <a class="header-anchor" href="#_5-如何和你当前的-java-面试主线结合" aria-label="Permalink to “5. 如何和你当前的 Java 面试主线结合”">​</a></h2><ul><li>每当你在 <code>Java / 数据库 / Redis / 框架</code> 模块里学完一篇文档，可以： <ol><li>把这篇文档内容丢给 LLM，让它帮你生成 <strong>5 道面试题 + 参考答案</strong>。</li><li>再让它帮你生成 <strong>一段 2～3 分钟的口述答案</strong>，你自己照着练。</li><li>用上面的小工具脚本，把这些输出自动落地成 Markdown 文件。</li></ol></li><li>这样，<strong>LLM 阶段的学习与面试主线是紧紧绑在一起的</strong>，而不是单独学“AI 知识点”。</li></ul>',37)])])}const u=a(r,[["render",n]]);export{p as __pageData,u as default};
